import{_ as t,o,c as i,a2 as a}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"ADR-021 — Documentation site at /docs/ via VitePress","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-021.md","filePath":"adr/ADR-021.md"}'),s={name:"adr/ADR-021.md"};function d(r,e,c,n,l,h){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="adr-021-—-documentation-site-at-docs-via-vitepress" tabindex="-1">ADR-021 — Documentation site at <code>/docs/</code> via VitePress <a class="header-anchor" href="#adr-021-—-documentation-site-at-docs-via-vitepress" aria-label="Permalink to &quot;ADR-021 — Documentation site at `/docs/` via VitePress&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-29 TA anchor · §stack</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The project&#39;s <code>docs/</code> directory contains 50+ markdown files spanning concept package (00–05), ADRs (TA + 19 + this one), RFCs, PRDs, UXSes, plus six prototype HTMLs. Until now these were viewed only on GitHub. As the project approached v1, two needs emerged:</p><ol><li>The docs are the project&#39;s single best onboarding surface — a public-facing docs site improves discoverability and shareability.</li><li>The prototypes are HTML files referenced throughout the docs; serving them at predictable URLs makes the cross-references actually clickable.</li></ol><p>Scope expansion landed late April 2026: build the docs into a static site and publish alongside the main app on GitHub Pages.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>VitePress</strong> as the static site generator, deployed at <code>/orrery/docs/</code> (sibling of the main app at <code>/orrery/</code>).</p><h3 id="stack-choice" tabindex="-1">Stack choice <a class="header-anchor" href="#stack-choice" aria-label="Permalink to &quot;Stack choice&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Considered</th><th>Result</th></tr></thead><tbody><tr><td><strong>VitePress</strong></td><td>✅ Chosen. Same Vite ecosystem we already run; markdown-first; auto-sidebar via <code>vitepress-sidebar</code>; lightweight (~1MB output); first-class search; clean URLs.</td></tr><tr><td>MkDocs / MkDocs Material</td><td>Rejected. Adds Python toolchain.</td></tr><tr><td>mdBook</td><td>Rejected. Adds Rust toolchain.</td></tr><tr><td>Docusaurus</td><td>Rejected. React-based; heavier than needed for engineering docs.</td></tr><tr><td>Astro Starlight</td><td>Plausible, more flexible than VitePress but heavier; deferred.</td></tr></tbody></table><h3 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h3><ul><li>Source: <code>docs/</code> (existing markdown + <code>docs/.vitepress/{config.ts,theme/}</code>)</li><li>Build output: <code>docs/.vitepress/dist/</code> (gitignored)</li><li>Deploy: copied into the main <code>build/docs/</code> artifact in CI; both app and docs ship via the same <code>peaceiris/actions-gh-pages@v3</code> step</li><li>URLs: <ul><li><code>chipi.github.io/orrery/</code> — main app</li><li><code>chipi.github.io/orrery/docs/</code> — docs site</li><li><code>chipi.github.io/orrery/docs/prototypes/P0X_*.html</code> — prototypes (copied verbatim from <code>docs/prototypes/</code> during <code>docs:build</code>)</li></ul></li></ul><h3 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h3><p>Default VitePress theme with one custom override: <code>--vp-c-brand-1: #4466ff</code> matching <code>src/lib/styles/tokens.css --color-accent</code>. Auto-sidebar from <code>vitepress-sidebar</code>. Local search (no Algolia dependency). No other branding — engineering docs prioritise readability over identity.</p><h3 id="linkage-between-app-and-docs" tabindex="-1">Linkage between app and docs <a class="header-anchor" href="#linkage-between-app-and-docs" aria-label="Permalink to &quot;Linkage between app and docs&quot;">​</a></h3><ul><li>Docs nav has an &quot;↗ Live App&quot; link to <code>chipi.github.io/orrery/</code></li><li>Main app does <strong>not</strong> link to docs (per user direction: docs is separate from product)</li></ul><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>VitePress reuses the Vite/SvelteKit ecosystem we already operate, avoiding a second toolchain. Markdown-first means the 50+ existing docs need no rewrites. Auto-sidebar keeps the burden low as we add docs over time. Static export integrates with the existing <code>peaceiris/actions-gh-pages</code> deploy in one extra step. The site is fast (build &lt; 2 s, page-load &lt; 200 ms typical) and the entire docs pipeline adds ~120 KB to the deployed artifact.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Embed docs into the SvelteKit app</strong> (e.g., via <code>mdsvex</code>) — couples docs build to app build; bloats the app bundle with markdown content; harder to navigate. Rejected.</li><li><strong>Separate gh-pages-docs repo</strong> — clean separation but separate URL hurts discovery; an extra repo to maintain. Rejected.</li><li><strong>No docs site, just GitHub view</strong> — current state pre-2026-04-29; works but offers no search, no nav, no public link. Replaced by this decision.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong></p><ul><li>Public docs at a stable URL; markdown stays the source of truth</li><li>Prototypes accessible at predictable URLs from anywhere in the docs</li><li>One deploy pipeline; one artifact; one gh-pages branch</li><li>Search works out of the box</li></ul><p><strong>Negative:</strong></p><ul><li>Two npm dependencies added (<code>vitepress</code>, <code>vitepress-sidebar</code>) — both small and well-maintained</li><li>Build time grows by ~2s for the docs step in CI</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Config: <code>docs/.vitepress/config.ts</code> (auto-sidebar via <code>vitepress-sidebar.generateSidebar</code>)</li><li>Theme override: <code>docs/.vitepress/theme/{index.ts,custom.css}</code></li><li>npm scripts: <code>docs:dev</code>, <code>docs:build</code>, <code>docs:preview</code></li><li>CI: <code>preview.yml</code> runs <code>docs:build</code> with <code>DOCS_BASE=/orrery/docs/</code>, then <code>cp -R docs/.vitepress/dist build/docs</code></li><li>ESLint ignores <code>docs/.vitepress/{dist,cache}/</code></li></ul>',27)])])}const b=t(s,[["render",d]]);export{u as __pageData,b as default};
